namespace ProductReviews.Services
{
    using System.Net;

    /// <summary>
    /// Sanitizes user-submitted review text to allow ONLY basic formatting
    /// tags: &lt;b&gt;, &lt;i&gt;, &lt;strong&gt;, &lt;em&gt;.
    /// All other HTML is escaped. This prevents XSS while allowing
    /// limited rich formatting.
    /// </summary>
    public interface IHtmlSanitizerService
    {
        string Sanitize(string untrustedInput);
    }

    public class ReviewHtmlSanitizerService : IHtmlSanitizerService
    {
        // Allowed tags (opening and closing) — no attributes allowed
        private static readonly string[] AllowedTags = { "b", "i", "strong", "em" };

        /// <summary>
        /// Sanitizes user input by:
        /// 1. HTML-encoding the entire input (neutralizes all HTML).
        /// 2. Selectively restoring ONLY the allowed formatting tags.
        /// This is a whitelist approach — everything is escaped first,
        /// then only known-safe patterns are restored.
        /// </summary>
        public string Sanitize(string untrustedInput)
        {
            if (string.IsNullOrEmpty(untrustedInput))
                return string.Empty;

            // Step 1: Fully HTML-encode everything. This neutralizes ALL HTML,
            // including any malicious scripts, event handlers, etc.
            string encoded = WebUtility.HtmlEncode(untrustedInput);

            // Step 2: Restore only the specific allowed tags from their encoded form.
            // Because we encoded first, we know the only angle brackets present
            // are the encoded versions (&lt; and &gt;). We selectively unencode
            // ONLY the exact patterns that match our whitelist.
            foreach (string tag in AllowedTags)
            {
                // Restore opening tags: &lt;b&gt; -> <b>
                // Only match the exact tag with no attributes (no spaces allowed)
                string encodedOpen = $"&lt;{tag}&gt;";
                string safeOpen = $"<{tag}>";
                encoded = Regex.Replace(encoded, Regex.Escape(encodedOpen), safeOpen, RegexOptions.IgnoreCase);

                // Restore closing tags: &lt;/b&gt; -> </b>
                string encodedClose = $"&lt;/{tag}&gt;";
                string safeClose = $"</{tag}>";
                encoded = Regex.Replace(encoded, Regex.Escape(encodedClose), safeClose, RegexOptions.IgnoreCase);
            }

            // Step 3: Convert newlines to <br> for readability
            encoded = encoded.Replace("\r\n", "<br>").Replace("\n", "<br>");

            return encoded;
        }
    }
}

