namespace ProductReviews.Controllers
{
    using ProductReviews.Data;
    using ProductReviews.Models;
    using ProductReviews.Services;

    public class ProductController : Controller
    {
        private readonly AppDbContext _db;
        private readonly IHtmlSanitizerService _sanitizer;

        public ProductController()
        {
            _db = new AppDbContext();
            _sanitizer = new ReviewHtmlSanitizerService();
        }

        public ProductController(AppDbContext db, IHtmlSanitizerService sanitizer)
        {
            _db = db;
            _sanitizer = sanitizer;
        }

        // GET: /Product/Details/5
        [HttpGet]
        public ActionResult Details(int id)
        {
            var product = _db.Products.Find(id);
            if (product == null)
                return HttpNotFound();

            var reviews = _db.Reviews
                .Where(r => r.ProductId == id)
                .OrderByDescending(r => r.CreatedAt)
                .ToList();

            var reviewViewModels = reviews.Select(r => new ReviewViewModel
            {
                Id = r.Id,
                // AuthorName will be rendered with @Model.AuthorName (auto-encoded by Razor)
                AuthorName = r.AuthorName,
                Rating = r.Rating,
                // SECURE: Sanitize the comment to allow only safe formatting tags.
                // The raw DB content is never rendered directly.
                SanitizedCommentHtml = _sanitizer.Sanitize(r.Comment),
                CreatedAt = r.CreatedAt
            }).ToList();

            var viewModel = new ProductDetailViewModel
            {
                Product = product,
                Reviews = reviewViewModels,
                NewReview = new ReviewSubmitModel { ProductId = id },
                AverageRating = reviews.Any() ? reviews.Average(r => r.Rating) : 0
            };

            return View(viewModel);
        }

        // POST: /Product/SubmitReview
        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult SubmitReview(ReviewSubmitModel model)
        {
            if (!ModelState.IsValid)
            {
                // Re-load the product page with validation errors
                return RedirectToAction("Details", new { id = model.ProductId });
            }

            var product = _db.Products.Find(model.ProductId);
            if (product == null)
                return HttpNotFound();

            var review = new Review
            {
                ProductId = model.ProductId,
                // Store the raw user input in the database.
                // Sanitization happens at render time, not storage time.
                AuthorName = model.AuthorName,
                Rating = model.Rating,
                Comment = model.Comment,
                CreatedAt = DateTime.UtcNow
            };

            _db.Reviews.Add(review);
            _db.SaveChanges();

            TempData["SuccessMessage"] = "Your review has been submitted successfully!";
            return RedirectToAction("Details", new { id = model.ProductId });
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _db.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}

